import React from 'react';
import { graphql, Link } from 'gatsby';
import PropTypes from 'prop-types';
import { Helmet } from 'react-helmet';
import styled from 'styled-components';
import { Layout } from '@components';

const StyledWorkContainer = styled.main`
  max-width: 980px;
`;

const StyledWorkHeader = styled.header`
  margin-bottom: 42px;

  .summary {
    margin-top: 14px;
    max-width: 72ch;
    font-size: var(--fz-md);
    line-height: 1.68;
    color: var(--dark-slate);
  }
`;

const StyledMeta = styled.div`
  ${({ theme }) => theme.mixins.resetList};
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 12px;
  margin: 26px 0 0;

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }

  .meta-card {
    border: 1px solid var(--lightest-navy);
    border-radius: var(--border-radius);
    background-color: var(--surface-secondary);
    padding: 14px 16px;
  }

  .meta-label {
    margin: 0;
    color: var(--light-slate);
    font-family: var(--font-mono);
    font-size: var(--fz-xxs);
    text-transform: uppercase;
  }

  .meta-value {
    margin: 4px 0 0;
    color: var(--lightest-slate);
    font-size: var(--fz-md);
    font-weight: 600;
  }
`;

const StyledActions = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-top: 24px;

  .primary {
    ${({ theme }) => theme.mixins.button};
  }

  .secondary {
    ${({ theme }) => theme.mixins.smallButton};
  }
`;

const StyledInfoGrid = styled.section`
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
  margin: 40px 0;

  @media (max-width: 900px) {
    grid-template-columns: 1fr;
  }

  .info-card {
    border: 1px solid var(--lightest-navy);
    border-radius: var(--border-radius);
    background-color: var(--surface-secondary);
    padding: 16px;
  }

  .info-title {
    margin: 0 0 12px;
    font-size: var(--fz-md);
    color: var(--lightest-slate);
    font-weight: 700;
  }

  .info-list {
    ${({ theme }) => theme.mixins.resetList};

    li {
      position: relative;
      margin-bottom: 8px;
      padding-left: 16px;
      font-size: var(--fz-sm);
      color: var(--dark-slate);
      line-height: 1.55;

      &:before {
        content: '•';
        position: absolute;
        left: 0;
        color: var(--green);
      }
    }
  }
`;

const StyledWorkContent = styled.div`
  margin-bottom: 100px;

  h2,
  h3 {
    margin: 1.8em 0 0.7em;
  }

  p {
    margin: 0 0 1em;
    line-height: 1.72;
    color: var(--dark-slate);
  }
`;

const WorkTemplate = ({ data, location }) => {
  const { frontmatter, html } = data.markdownRemark;
  const {
    title,
    company,
    role,
    timeline,
    summary,
    liveUrl,
    repositoryUrl,
    architecture,
    roadmap,
    outcomes,
  } = frontmatter;

  return (
    <Layout location={location}>
      <Helmet title={`${title} Case Study`} />

      <StyledWorkContainer>
        <span className="breadcrumb">
          <span className="arrow">&larr;</span>
          <Link to="/#projects">Back to Work</Link>
        </span>

        <StyledWorkHeader>
          <p className="overline">Case Study</p>
          <h1 className="medium-heading">{title}</h1>
          {summary && <p className="summary">{summary}</p>}

          <StyledMeta>
            <div className="meta-card">
              <p className="meta-label">Company</p>
              <p className="meta-value">{company}</p>
            </div>
            <div className="meta-card">
              <p className="meta-label">Role</p>
              <p className="meta-value">{role}</p>
            </div>
            <div className="meta-card">
              <p className="meta-label">Timeline</p>
              <p className="meta-value">{timeline}</p>
            </div>
          </StyledMeta>

          <StyledActions>
            {liveUrl && (
              <a className="primary" href={liveUrl} target="_blank" rel="noreferrer">
                Visit Product
              </a>
            )}
            {repositoryUrl && (
              <a className="secondary" href={repositoryUrl} target="_blank" rel="noreferrer">
                View Repository
              </a>
            )}
          </StyledActions>
        </StyledWorkHeader>

        <StyledInfoGrid>
          {architecture?.length > 0 && (
            <article className="info-card">
              <h2 className="info-title">Technical Architecture</h2>
              <ul className="info-list">
                {architecture.map((item, i) => (
                  <li key={i}>{item}</li>
                ))}
              </ul>
            </article>
          )}

          {roadmap?.length > 0 && (
            <article className="info-card">
              <h2 className="info-title">Delivery Roadmap</h2>
              <ul className="info-list">
                {roadmap.map((item, i) => (
                  <li key={i}>{item}</li>
                ))}
              </ul>
            </article>
          )}

          {outcomes?.length > 0 && (
            <article className="info-card">
              <h2 className="info-title">Outcomes</h2>
              <ul className="info-list">
                {outcomes.map((item, i) => (
                  <li key={i}>{item}</li>
                ))}
              </ul>
            </article>
          )}
        </StyledInfoGrid>

        <StyledWorkContent dangerouslySetInnerHTML={{ __html: html }} />
      </StyledWorkContainer>
    </Layout>
  );
};

WorkTemplate.propTypes = {
  data: PropTypes.object.isRequired,
  location: PropTypes.object.isRequired,
};

export default WorkTemplate;

export const pageQuery = graphql`
  query($slug: String!) {
    markdownRemark(frontmatter: { slug: { eq: $slug } }) {
      html
      frontmatter {
        title
        slug
        company
        role
        timeline
        summary
        liveUrl
        repositoryUrl
        architecture
        roadmap
        outcomes
      }
    }
  }
`;
